class ResourceOrdering:
 def __init__(self, resource_order):
 self.resource_order = resource_order

 def request_resource(self, process, resource):
 if resource not in self.resource_order:
 raise ValueError("Resource not in order")
 elif not all(r in process.requested_resources for r in self.resource_order[:self.resource_order.index(resource)]):
 raise ValueError("Resources out of order")
 process.requested_resources.append(resource)

# Example usage:
resource_order = ['R1', 'R2', 'R3']
process = type('Process', (), {'requested_resources': []})
ordering = ResourceOrdering(resource_order)
ordering.request_resource(process, 'R1')
ordering.request_resource(process, 'R2')
ordering.request_resource(process, 'R3')

#include <stdio.h>
#include <stdlib.h>

#define MAX_RESOURCES 10

char* resource_order[MAX_RESOURCES];
int num_resources;

void request_resource(char* process, char* resource) {
 int i;
 for (i = 0; i < num_resources; i++) {
 if (strcmp(resource_order[i], resource) == 0) {
 break;
 }
 }
 if (i == num_resources) {
 printf("Error: Resource not in order\n");
 exit(1);
 }
 // Simulate process requesting resources in order
 for (int j = 0; j < i; j++) {
 printf("Process %s requests resource %s\n", process, resource_order[j]);
 }
}

int main() {
 num_resources = 3;
 resource_order[0] = "R1";
 resource_order[1] = "R2";
 resource_order[2] = "R3";
 request_resource("P1", "R1");
 request_resource("P1", "R2");
 request_resource("P1", "R3");
 return 0;
}
